def priority(el: tuple, n: int, w: int) -> float:
    import math

    # Count isolated non-zero elements (neighbors both zero)
    isolated = 0
    for i in range(n):
        if el[i] != 0:
            left_zero = (i == 0) or (el[i-1] == 0)
            right_zero = (i == n-1) or (el[i+1] == 0)
            if left_zero and right_zero:
                isolated += 1

    # Count clusters of non-zero elements (runs of non-zero)
    in_cluster = False
    clusters = 0
    for i in range(n):
        if el[i] != 0 and not in_cluster:
            clusters += 1
            in_cluster = True
        elif el[i] == 0:
            in_cluster = False

    # Maximum zero-run length
    max_zero_run = 0
    current_run = 0
    for x in el:
        if x == 0:
            current_run += 1
        else:
            max_zero_run = max(max_zero_run, current_run)
            current_run = 0
    max_zero_run = max(max_zero_run, current_run)

    # Score: reward isolated non-zeros and many clusters, penalize long zero runs
    return isolated * 5.0 + clusters * 3.0 - max_zero_run * 4.0

def priority(el: tuple, n: int, w: int) -> float:
    import math

    # Count transitions zero->non-zero and non-zero->zero separately
    trans_01 = 0
    trans_10 = 0
    for i in range(1, n):
        if el[i-1] == 0 and el[i] != 0:
            trans_01 += 1
        elif el[i-1] != 0 and el[i] == 0:
            trans_10 += 1

    # Longest zero run
    max_zero_run = 0
    current_zero = 0
    # Longest non-zero run
    max_nonzero_run = 0
    current_nonzero = 0
    for x in el:
        if x == 0:
            current_zero += 1
            if current_zero > max_zero_run:
                max_zero_run = current_zero
            current_nonzero = 0
        else:
            current_nonzero += 1
            if current_nonzero > max_nonzero_run:
                max_nonzero_run = current_nonzero
            current_zero = 0

    # Entropy of non-zero positions
    non_zero_indices = [i for i, x in enumerate(el) if x != 0]
    if len(non_zero_indices) == 0:
        return 0.0
    positions = [i / (n - 1) for i in non_zero_indices]
    entropy = 0.0
    for p in positions:
        if 0 < p < 1:
            if p > 0:
                entropy -= p * math.log(p, n)
            if (1 - p) > 0:
                entropy -= (1 - p) * math.log(1 - p, n)
    entropy /= len(non_zero_indices)

    # Avoid division by zero
    denom = max_zero_run + max_nonzero_run
    if denom == 0:
        denom = 1

    score = (trans_01 * trans_10) / denom * (1.0 + entropy)
    return score
